// Micah Bragg - CPI Global - Updated via REST API

var ds = new DataSet();
var dt = new DataTable("LaborDetails");
var x 
//mica testing 05/26/2004
//micah micah from antigracity
//Micah testing 06/20/2003
var colNames = new List<string>()
{
    "LaborDtl_TimeStatus",
    "LaborDtl_JobNum",
    "JobHead_JobGroup_c",
    "LaborDtl_AssemblySeq",
    "JobAsmbl_PartNum",
    "JobAsmbl_Description",
    "LaborDtl_LaborQty",
    "LaborDtl_DiscrepQty",
    "JobOper_RunQty",
    "JobOper_OpComplete",
    "Calculated_QtyRem",
    "LaborDtl_LaborHedSeq",
    "LaborDtl_LaborDtlSeq",
    "LaborDtl_PaintLine_c",
    "Calculated_GoodQty",
    "Calculated_BadQty",
    "LaborDtl_PaintLineDate_c",
    "LaborDtl_ClockInDate",
    "LaborDtl_ClockinTime",
    "Calculated_ClockInTime",
    "Calculated_UTCClockInTime",
    "Calculated_TempClock",
    "Calculated_WIPMin",
    "LaborHed_LaborHedSeq",
    "LaborDtl_SubmittedBy",
    "LaborDtl_ActiveTrans",
    "LaborDtl_ShortChar01",
    "LaborDtl_OpCode",
    "LaborDtl_OprSeq",
    "Calculated_WIPMinDec",
    "Calculated_Msg",
    "LaborDtl_CreateTime",
    "LaborDtl_CreateDate",
    "Calculated_AutoReceive",
    "JobOper_IUM",
    "ResourceGroup_OutputWhse",
    "ResourceGroup_OutputBinNum",
    "ResourceGroup_Plant",
    "Calculated_MaxPartTran",
    "LaborDtl_PaintLineSection_c",
    "Selected",
    "RowMod",
};

foreach (var col in colNames)
{
    dt.Columns.Add(new DataColumn(col));
}
ds.Tables.Add(dt);

var currentPlant = callContextClient.CurrentPlant;
var plantPnt = currentPlant + "PNT";
var cutoffDate = DateTime.Today.AddDays(-45);

var PLRecs = (
    from LD in Db.LaborDtl
    join JobAsm in Db.JobAsmbl
        on new
        {
            LD.Company,
            LD.JobNum,
            LD.AssemblySeq,
            Plant = currentPlant,
        } equals new
        {
            JobAsm.Company,
            JobAsm.JobNum,
            JobAsm.AssemblySeq,
            JobAsm.Plant,
        }
    join JobOper in Db.JobOper
        on new
        {
            LD.Company,
            LD.JobNum,
            LD.AssemblySeq,
            LD.OprSeq,
        } equals new
        {
            JobOper.Company,
            JobOper.JobNum,
            JobOper.AssemblySeq,
            JobOper.OprSeq,
        }
    join JobOpDtl in Db.JobOpDtl
        on new
        {
            JobOper.Company,
            JobOper.JobNum,
            JobOper.AssemblySeq,
            JobOper.OprSeq,
        } equals new
        {
            JobOpDtl.Company,
            JobOpDtl.JobNum,
            JobOpDtl.AssemblySeq,
            JobOpDtl.OprSeq,
        }
    join RsrcGrp in Db.ResourceGroup
        on new { JobOpDtl.Company, JobOpDtl.ResourceGrpID } equals new
        {
            RsrcGrp.Company,
            RsrcGrp.ResourceGrpID,
        }
    join JobHead in Db.JobHead
        on new { LD.Company, LD.JobNum } equals new { JobHead.Company, JobHead.JobNum }
    join LaborHed in Db.LaborHed
        on new { LD.Company, LD.LaborHedSeq } equals new { LaborHed.Company, LaborHed.LaborHedSeq }
    where
        LD.PaintLine_c == false
        && LD.ClockInDate > cutoffDate
        && LD.LaborQty > 0
        && JobHead.JobClosed == false
        && JobHead.JobEngineered == true
        && JobHead.JobReleased == true
        && LD.OpCode.StartsWith(plantPnt)
    select new
    {
        // LaborDtl
        LD_TimeStatus = LD.TimeStatus,
        LD_JobNum = LD.JobNum,
        LD_AssemblySeq = LD.AssemblySeq,
        LD_LaborQty = LD.LaborQty,
        LD_DiscrepQty = LD.DiscrepQty,
        LD_LaborHedSeq = LD.LaborHedSeq,
        LD_LaborDtlSeq = LD.LaborDtlSeq,
        LD_PaintLine_c = LD.PaintLine_c,
        LD_PaintLineDate_c = LD.PaintLineDate_c,
        LD_ClockInDate = LD.ClockInDate,
        LD_ClockinTime = LD.ClockinTime,
        LD_SubmittedBy = LD.SubmittedBy,
        LD_ActiveTrans = LD.ActiveTrans,
        LD_ShortChar01 = LD.ShortChar01,
        LD_OpCode = LD.OpCode,
        LD_OprSeq = LD.OprSeq,
        LD_CreateTime = LD.CreateTime,
        LD_CreateDate = LD.CreateDate,
        LD_PaintLineSection_c = LD.PaintLineSection_c,

        // JobHead / JobAsmbl / JobOper / LaborHed
        JH_JobGroup_c = JobHead.JobGroup_c,

        JA_PartNum = JobAsm.PartNum,
        JA_Description = JobAsm.Description,
        JA_AutoRecOpr = JobAsm.AutoRecOpr,

        JO_RunQty = JobOper.RunQty,
        JO_QtyCompleted = JobOper.QtyCompleted,
        JO_OpComplete = JobOper.OpComplete,
        JO_IUM = JobOper.IUM,

        LH_LaborHedSeq = LaborHed.LaborHedSeq,

        // ResourceGroup
        RG_OutputWhse = RsrcGrp.OutputWhse,
        RG_OutputBinNum = RsrcGrp.OutputBinNum,
        RG_Plant = RsrcGrp.Plant,
    }
)
    .OrderBy(x => x.LD_ClockInDate) // OLDEST FIRST (FIFO)
    .ThenBy(x => x.LD_ClockinTime) // Then by earliest time
    .Take(500)
    .ToList();

foreach (var rec in PLRecs)
{
    var row = dt.NewRow();
    row["LaborDtl_TimeStatus"] = rec.LD_TimeStatus;
    row["LaborDtl_JobNum"] = rec.LD_JobNum;
    row["JobHead_JobGroup_c"] = rec.JH_JobGroup_c;
    row["LaborDtl_AssemblySeq"] = rec.LD_AssemblySeq;
    row["JobAsmbl_PartNum"] = rec.JA_PartNum;
    row["JobAsmbl_Description"] = rec.JA_Description;
    row["LaborDtl_LaborQty"] = rec.LD_LaborQty;
    row["LaborDtl_DiscrepQty"] = rec.LD_DiscrepQty;
    row["JobOper_RunQty"] = rec.JO_RunQty;
    row["JobOper_OpComplete"] = rec.JO_OpComplete;
    row["Calculated_QtyRem"] = rec.JO_RunQty - rec.JO_QtyCompleted;
    row["LaborDtl_LaborHedSeq"] = rec.LD_LaborHedSeq;
    row["LaborDtl_LaborDtlSeq"] = rec.LD_LaborDtlSeq;
    row["LaborDtl_PaintLine_c"] = rec.LD_PaintLine_c;
    row["Calculated_GoodQty"] = rec.LD_LaborQty;
    row["Calculated_BadQty"] = 0;
    row["LaborDtl_PaintLineDate_c"] = rec.LD_PaintLineDate_c;
    row["LaborDtl_ClockInDate"] = rec.LD_ClockInDate;
    row["LaborDtl_ClockinTime"] = rec.LD_ClockinTime;

    // CALCULATE CLOCK-IN TIMES AND WIP
    if (rec.LD_ClockInDate != null && rec.LD_ClockinTime > 0)
    {
        // ClockinTime is stored as seconds since midnight
        DateTime clockInDateTime = ((DateTime)rec.LD_ClockInDate).AddSeconds(
            (double)rec.LD_ClockinTime
        );

        // Format local clock-in time (HH:mm:ss)
        row["Calculated_ClockInTime"] = clockInDateTime.ToString("HH:mm:ss");

        // Format UTC clock-in time
        DateTime utcClockIn = clockInDateTime.ToUniversalTime();
        row["Calculated_UTCClockInTime"] = utcClockIn.ToString("HH:mm:ss");

        // Calculate WIP time (time since clock-in)
        TimeSpan wipTime = DateTime.Now - clockInDateTime;

        // Format as H:MM (e.g., "2:45" or "15:30")
        int totalHours = (int)wipTime.TotalHours;
        int minutes = wipTime.Minutes;
        row["Calculated_WIPMin"] = $"{totalHours}:{minutes:D2}";

        // Store decimal minutes for calculations
        row["Calculated_WIPMinDec"] = (decimal)wipTime.TotalMinutes;
    }
    else
    {
        // No valid clock-in data
        row["Calculated_ClockInTime"] = " ";
        row["Calculated_UTCClockInTime"] = " ";
        row["Calculated_WIPMin"] = "0:00";
        row["Calculated_WIPMinDec"] = 0.00m;
    }

    row["Calculated_TempClock"] = DateTime.Today;
    row["LaborHed_LaborHedSeq"] = rec.LH_LaborHedSeq;
    row["LaborDtl_SubmittedBy"] = rec.LD_SubmittedBy;
    row["LaborDtl_ActiveTrans"] = rec.LD_ActiveTrans;
    row["LaborDtl_ShortChar01"] = rec.LD_ShortChar01;
    row["LaborDtl_OpCode"] = rec.LD_OpCode;
    row["LaborDtl_OprSeq"] = rec.LD_OprSeq;
    row["Calculated_Msg"] = "";
    row["LaborDtl_CreateTime"] = rec.LD_CreateTime;
    row["LaborDtl_CreateDate"] = rec.LD_CreateDate;
    row["Calculated_AutoReceive"] = rec.JA_AutoRecOpr == rec.LD_OprSeq ? 1 : 0;
    row["JobOper_IUM"] = rec.JO_IUM;
    row["ResourceGroup_OutputWhse"] = rec.RG_OutputWhse;
    row["ResourceGroup_OutputBinNum"] = rec.RG_OutputBinNum;
    row["ResourceGroup_Plant"] = rec.RG_Plant;
    row["Calculated_MaxPartTran"] = 0;
    row["LaborDtl_PaintLineSection_c"] = rec.LD_PaintLineSection_c;
    row["Selected"] = false;
    row["RowMod"] = String.Empty;
    dt.Rows.Add(row);
}

output = ds;
count = dt.Rows.Count;
","Usings":""}

{"Code":"List<DataRow> deleteRows = new List<DataRow>();
var msg = string.Empty;
var step = string.Empty;
var tz = Db.Plant
    .Where(
        p =>
            p.Company == callContextClient.CurrentCompany
            && p.Plant1 == callContextClient.CurrentPlant
    )
    .Select(p => p.TimeZoneID)
    .FirstOrDefault();

System.TimeZoneInfo tZone = System.TimeZoneInfo.FindSystemTimeZoneById(tz);
callContextBpmData.Checkbox01 = true;
callContextBpmData.Checkbox02 = true;
oldDS = ds; 
try
{
    foreach (System.Data.DataRow row in ds.Tables["UnloadGrid"].Rows)
    {
        var r = row;
        var unapp = false;
        var lbrrecordupdated = false;
        if (r["Selected"] != DBNull.Value && Convert.ToBoolean(r["Selected"]))
        {
          
            int laborHedSeq = !string.IsNullOrEmpty(r["LaborHed_LaborHedSeq"]?.ToString())
                ? Convert.ToInt32(r["LaborHed_LaborHedSeq"].ToString())
                : 0;
           step = "lbrhed";
            int laborDtlSeq = !string.IsNullOrEmpty(r["LaborDtl_LaborDtlSeq"]?.ToString())
                ? Convert.ToInt32(r["LaborDtl_LaborDtlSeq"].ToString())
                : 0;

            decimal badQty = !string.IsNullOrEmpty(r["Calculated_BadQty"]?.ToString())
                ? Convert.ToDecimal(r["Calculated_BadQty"].ToString())
                : 0;
                step = "goodqty";
            decimal goodQty = !string.IsNullOrEmpty(r["Calculated_GoodQty"]?.ToString())
                ? Convert.ToDecimal(r["Calculated_GoodQty"].ToString())
                : 0;
             step = "lbrhed 2";   
            if(goodQty + badQty == 0)
            {
                r["Calculated_Msg"] = "Good and/or Non Conf columns must have valid value.";
                continue;
            }
            
            if(goodQty < 0)
            {
                r["Calculated_Msg"] = "Good and/or Non Conf columns must have valid value > 0.";
                continue;
            }

            CallService<Erp.Contracts.LaborSvcContract>(bo =>
            {
                var lbrTS = bo.GetDetail(laborHedSeq, laborDtlSeq);
                var lbrRow = lbrTS.LaborDtl.Find(x => x.LaborDtlSeq == laborDtlSeq);
                if (lbrRow != null)
                {
                    laborDtlSeq = laborDtlSeq;
                    laborHedSeq = laborHedSeq;
                    try
                    { 
                      step = "beflbrqty";
                        decimal laborQty = !string.IsNullOrEmpty(r["LaborDtl_LaborQty"]?.ToString())
                            ? Convert.ToDecimal(r["LaborDtl_LaborQty"].ToString())
                            : 0m;
                        step = "laborqty";
                        decimal RunQty = !string.IsNullOrEmpty(r["JobOper_RunQty"]?.ToString())
                            ? Convert.ToDecimal(r["JobOper_RunQty"].ToString())
                            : 0m;
                        step = "runqty";
                        string TimeStatus = !string.IsNullOrEmpty(
                            r["LaborDtl_TimeStatus"]?.ToString()
                        )
                            ? r["LaborDtl_TimeStatus"].ToString()
                            : string.Empty;

                        string jobNum = !string.IsNullOrEmpty(r["LaborDtl_JobNum"]?.ToString())
                            ? r["LaborDtl_JobNum"].ToString()
                            : string.Empty;

                        int assemblySeq = !string.IsNullOrEmpty(
                            r["LaborDtl_AssemblySeq"]?.ToString()
                        )
                            ? Convert.ToInt32(r["LaborDtl_AssemblySeq"].ToString())
                            : 0;

                        int oprSeq = !string.IsNullOrEmpty(r["LaborDtl_OprSeq"]?.ToString())
                            ? Convert.ToInt32(r["LaborDtl_OprSeq"].ToString())
                            : 0;

                        string opCode = !string.IsNullOrEmpty(r["LaborDtl_OpCode"]?.ToString())
                            ? r["LaborDtl_OpCode"].ToString()
                            : string.Empty;

                        string company = callContextClient.CurrentCompany;
                        if (goodQty != laborQty)
                        {
                            if (TimeStatus == "A")
                            {
                                lbrRow.TimeStatus = "E";
                                lbrRow.ApprovedDate = null;
                                bo.RecallFromApproval(ref lbrTS, false, out msg);
                                bo.Update(ref lbrTS);
                                callContextBpmData.Checkbox01 = true;
                                callContextBpmData.Checkbox02 = true;
                                unapp = true;
                            }

                            lbrRow.LaborQty = goodQty;
                            lbrRow.RowMod = "U";
                            step = "before def com";
                            bo.DefaultComplete(ref lbrTS, !(goodQty < RunQty), out msg);
                            step = "after def com";
                            lbrrecordupdated = true;
                        }

                        if (!lbrrecordupdated)
                        {
                            callContextBpmData.Checkbox01 = true;
                            callContextBpmData.Checkbox02 = true;

                            var ttlbr = Db.LaborDtl.FirstOrDefault(
                                ld =>
                                    ld.Company == company
                                    && ld.LaborHedSeq == laborHedSeq
                                    && ld.LaborDtlSeq == laborDtlSeq
                            );

                            if (ttlbr != null)
                            {
                                ttlbr.PaintLineDate_c = null;
                                ttlbr.PaintLine_c = true;
                                ttlbr.ShortChar01 = string.Empty;
                                Db.SaveChanges();
                            }
                        }
                        else
                        {
                            lbrRow["PaintLineDate_c"] = false
                                ? System.TimeZoneInfo.ConvertTime(System.DateTime.Now, tZone)
                                : System.DateTime.Now;
                            lbrRow["PaintLine_c"] = true;
                            lbrRow["ShortChar01"] = printer;
                            lbrRow.ExpenseCode = "DIRECT";
                            bo.LaborRateCalc(ref lbrTS);
                            lbrRow.ClockInDate = lbrRow.PayrollDate;
                            lbrRow.NewDifDateFlag = 1;
                            bo.Update(ref lbrTS);
                            callContextBpmData.Checkbox01 = true;
                            callContextBpmData.Checkbox02 = true;

                            if (unapp)
                            {
                                var tLbr = Db.LaborDtl.FirstOrDefault(
                                    ld =>
                                        ld.Company == Session.CompanyID
                                        && ld.LaborHedSeq == laborHedSeq
                                        && ld.LaborDtlSeq == laborDtlSeq
                                );

                                if (tLbr != null)
                                {
                                    tLbr.TimeStatus = "A";
                                    tLbr.ApprovedDate = null;
                                    Db.SaveChanges();
                                }
                            }
                        }
                        if (goodQty > 0 && !string.IsNullOrEmpty(printer))
                        {
                            this.EfxLib.DemandBTLabels.PrintLabel(
                                jobNum,
                                Convert.ToInt32(RunQty),
                                assemblySeq,
                                oprSeq,
                                0,
                                0,
                                0,
                                string.Empty,
                                string.Empty,
                                string.Empty,
                                string.Empty,
                                Convert.ToInt32(goodQty),
                                1,
                                "MtlTag",
                                printer,
                                1,
                                string.Empty,
                                string.Empty,
                                string.Empty,
                                0,
                                string.Empty,
                                string.Empty,
                                string.Empty,
                                0,
                                string.Empty
                            );
                        }

                        deleteRows.Add(row);
                    }
                    catch (Exception e)
                    {
                        output = $" {e.Message} + {step}";
                    }
                    ;
                }
            });
        }
    }

    foreach (var x in deleteRows)
    {
        ds.Tables["UnloadGrid"].Rows.Remove(x);
    }
    updatedDs = ds;
 
}
catch (Exception e)
{
    output = $"{e.Message}";
}
","Usings":""}
